{"code":"import json
import re

businesses_wifi_raw = json.loads(locals()['var_function-call-4873346791893292572']['results'])

def extract_state(description):
    match = re.search(r', ([A-Z]{2}),', description)
    if match:
        return match.group(1)
    return None

businesses_with_states = []
for business in businesses_wifi_raw:
    state = extract_state(business['description'])
    if state:
        business['state'] = state
        business['business_ref'] = business['business_id'].replace('businessid_', 'businessref_')
        business['business_id'] = business['business_id'] # Keep original for later if needed
        business_data = {'business_ref': business['business_ref'], 'state': business['state']}
        business_with_states.append(business_data)

print('__RESULT__:')
print(json.dumps(business_with_states))"}

